package com.oozie.example;

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.TimeZone;

/**
 * Oozie Coordinator Job Generator
 * Generates coordinator XML for scheduling Oozie workflows
 */
public class OozieCoordinatorScheduler {

    private String coordinatorName;
    private String workflowPath;
    private String datasetUriTemplate;
    private int frequencyDays;
    private Date startTime;
    private Date endTime;

    public OozieCoordinatorScheduler(String name, String workflowPath) {
        this.coordinatorName = name;
        this.workflowPath = workflowPath;
        this.frequencyDays = 1;
        this.startTime = new Date();
        this.endTime = new Date(System.currentTimeMillis() + 365L * 24 * 60 * 60 * 1000);
    }

    public void setDatasetUriTemplate(String template) {
        this.datasetUriTemplate = template;
    }

    public void setFrequency(int days) {
        this.frequencyDays = days;
    }

    public void setSchedule(Date start, Date end) {
        this.startTime = start;
        this.endTime = end;
    }

    /**
     * Generate Coordinator XML
     */
    public String generateCoordinatorXML() {
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm'Z'");
        sdf.setTimeZone(TimeZone.getTimeZone("UTC"));

        StringBuilder xml = new StringBuilder();
        xml.append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n");
        xml.append("<coordinator-app name=\"").append(coordinatorName).append("\"");
        xml.append(" frequency=\"${coord:days(").append(frequencyDays).append(")}\"\n");
        xml.append("                 start=\"").append(sdf.format(startTime)).append("\"\n");
        xml.append("                 end=\"").append(sdf.format(endTime)).append("\"\n");
        xml.append("                 timezone=\"UTC\"\n");
        xml.append("                 xmlns=\"uri:oozie:coordinator:0.5\">\n");

        // Dataset definition
        xml.append("    <datasets>\n");
        xml.append("        <dataset name=\"input-data\"\n");
        xml.append("                 frequency=\"${coord:days(").append(frequencyDays).append(")}\"\n");
        xml.append("                 initial-instance=\"").append(sdf.format(startTime)).append("\"\n");
        xml.append("                 timezone=\"UTC\">\n");
        xml.append("            <uri-template>\n");
        xml.append("                ").append(datasetUriTemplate).append("\n");
        xml.append("            </uri-template>\n");
        xml.append("        </dataset>\n");
        xml.append("    </datasets>\n");

        // Input events
        xml.append("    <input-events>\n");
        xml.append("        <data-in name=\"sensor-input\" dataset=\"input-data\">\n");
        xml.append("            <instance>${coord:current(0)}</instance>\n");
        xml.append("        </data-in>\n");
        xml.append("    </input-events>\n");

        // Action
        xml.append("    <action>\n");
        xml.append("        <workflow>\n");
        xml.append("            <app-path>").append(workflowPath).append("</app-path>\n");
        xml.append("            <configuration>\n");
        xml.append("                <property>\n");
        xml.append("                    <name>inputDir</name>\n");
        xml.append("                    <value>${coord:dataIn('sensor-input')}</value>\n");
        xml.append("                </property>\n");
        xml.append("            </configuration>\n");
        xml.append("        </workflow>\n");
        xml.append("    </action>\n");

        xml.append("</coordinator-app>");

        return xml.toString();
    }

    /**
     * Generate Bundle XML for grouping coordinators
     */
    public String generateBundleXML(String bundleName, String[] coordinatorPaths) {
        StringBuilder xml = new StringBuilder();
        xml.append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n");
        xml.append("<bundle-app name=\"").append(bundleName).append("\"\n");
        xml.append("             xmlns=\"uri:oozie:bundle:0.2\">\n");

        for (String coordPath : coordinatorPaths) {
            String coordName = extractCoordinatorName(coordPath);
            xml.append("    <coordinator name=\"").append(coordName).append("\">\n");
            xml.append("        <app-path>").append(coordPath).append("</app-path>\n");
            xml.append("    </coordinator>\n");
        }

        xml.append("</bundle-app>");
        return xml.toString();
    }

    private String extractCoordinatorName(String path) {
        String filename = path.substring(path.lastIndexOf('/') + 1);
        return filename.replace(".xml", "");
    }

    /**
     * Save coordinator XML to file
     */
    public void saveToFile(String filename) throws IOException {
        try (FileWriter writer = new FileWriter(filename)) {
            writer.write(generateCoordinatorXML());
        }
    }

    public static void main(String[] args) throws IOException {
        // Create hourly sensor data coordinator
        OozieCoordinatorScheduler hourlyScheduler = new OozieCoordinatorScheduler(
            "hourly-sensor-processing",
            "/user/oozie/workflows/sensor-processing-wf"
        );
        hourlyScheduler.setDatasetUriTemplate(
            "/data/sensors/${YEAR}/${MONTH}/${DAY}/${HOUR}"
        );
        hourlyScheduler.setFrequency(1); // Run every hour
        hourlyScheduler.setSchedule(
            new Date(),
            new Date(System.currentTimeMillis() + 30L * 24 * 60 * 60 * 1000)
        );

        String hourlyCoordXml = hourlyScheduler.generateCoordinatorXML();
        System.out.println("=== Hourly Coordinator XML ===");
        System.out.println(hourlyCoordXml);

        // Create daily summary coordinator
        OozieCoordinatorScheduler dailyScheduler = new OozieCoordinatorScheduler(
            "daily-sensor-summary",
            "/user/oozie/workflows/daily-summary-wf"
        );
        dailyScheduler.setDatasetUriTemplate(
            "/data/sensors/${YEAR}/${MONTH}/${DAY}"
        );
        dailyScheduler.setFrequency(1); // Run daily

        // Create bundle
        String bundleXml = hourlyScheduler.generateBundleXML("iot-analytics-bundle",
            new String[]{
                "/user/oozie/coordinators/hourly-sensor-processing.xml",
                "/user/oozie/coordinators/daily-sensor-summary.xml"
            }
        );

        System.out.println("\n=== Bundle XML ===");
        System.out.println(bundleXml);
    }
}
